const data = $input.first().json;
const body = (data.body && typeof data.body === 'object') ? data.body : data;

const user = (body.user && typeof body.user === 'object') ? body.user : {};
const currentMessage = body.currentMessage || '';
const history = Array.isArray(body.history) ? body.history : [];
const tasks = Array.isArray(body.tasks) ? body.tasks : [];

if (!currentMessage.trim()) {
  throw new Error('DEBUG - data keys: ' + JSON.stringify(Object.keys(data)) + ' | body keys: ' + JSON.stringify(Object.keys(body)) + ' | currentMessage: ' + JSON.stringify(body.currentMessage));
}

const today = new Date().toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowISO = tomorrow.toISOString().split('T')[0];

const userName = user.fullName || user.firstName || user.email || 'Usuario';
const userRole = user.role || 'estudiante';

const prioEmoji = { urgente: '🔴', alta: '🟠', media: '🟡', baja: '🟢' };
const taskList = tasks.length > 0
  ? tasks.map((t, i) => {
      const due = t.dueDate ? new Date(t.dueDate).toLocaleDateString('es-ES') : 'Sin fecha';
      const emoji = prioEmoji[t.priority] || '⚪';
      return `${i + 1}. [ID:${t.id}] ${emoji} ${t.title} | Estado: ${t.status} | Vence: ${due}`;
    }).join('\n')
  : 'No hay tareas registradas.';

const systemPrompt = `Eres un asistente personal inteligente integrado en TaskMaster. Puedes responder cualquier pregunta, dar consejos, conversar sobre cualquier tema, y además gestionar las tareas del usuario cuando te lo pida.\n\nFecha de hoy: ${today}\nUsuario: ${userName} (${userRole})\n\nTAREAS ACTUALES DEL USUARIO:\n${taskList}\n\nINSTRUCCIONES:\n- Responde SIEMPRE en español y en formato JSON válido.\n- Responde cualquier pregunta libremente, no solo sobre tareas.\n- Solo usa la lista de tareas si el usuario pregunta por ellas o pide crear/modificar una.\n- Sé natural, amigable y útil como un asistente general.\n\nFORMATO DE RESPUESTA:\n1. Respuesta normal: { "text": "tu respuesta" }\n2. Con acciones de tarea:\n{\n  "text": "Confirmación",\n  "actions": [\n    { "type": "create_task", "title": "Nombre", "dueDate": "2026-05-21T10:00:00Z", "priority": "media", "description": "opcional" },\n    { "type": "update_task", "taskId": "id-exacto", "dueDate": "2026-05-25T00:00:00Z", "priority": "alta", "status": "en_proceso" }\n  ]\n}\n\nReglas: mañana = ${tomorrowISO}T09:00:00Z | priority: baja/media/alta/urgente | status: pendiente/en_proceso/finalizada | solo IDs de la lista`;

const prevMessages = history
  .filter(m => m.text && m.text.trim())
  .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.text }));

const messages = [
  { role: 'system', content: systemPrompt },
  ...prevMessages,
  { role: 'user', content: currentMessage }
];

return [{ json: { messages } }];

const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { text: content || 'El asistente no pudo responder. Intenta de nuevo.' };
}

const text = typeof parsed.text === 'string' ? parsed.text : JSON.stringify(parsed);
const actions = Array.isArray(parsed.actions) && parsed.actions.length > 0 ? parsed.actions : undefined;

const result = { text };
if (actions) result.actions = actions;

return [{ json: result }];
